const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

const f = body.filters || {};
const limit = Math.min(Math.max(parseInt(f.limit, 10) || 100, 1), 500);
const sinceIso = f.since || null;

const qs = ['select=id,module_name,alert_type,severity,title,message,details,status,triggered_at,acknowledged_at,acknowledged_by,resolved_at,resolution_notes,aggregation_key']
  .concat([
    'module_name=eq.ciro',
    'order=triggered_at.desc',
    'limit=' + limit
  ]);
if (sinceIso) qs.push('triggered_at=gte.' + encodeURIComponent(sinceIso));
if (f.alert_type && f.alert_type !== 'all') qs.push('alert_type=eq.' + encodeURIComponent(f.alert_type));
if (f.status && f.status !== 'all') qs.push('status=eq.' + encodeURIComponent(f.status));
if (f.severity && f.severity !== 'all') qs.push('severity=eq.' + encodeURIComponent(f.severity));

return { json: { token: token, qs: qs.join('&'), filters: f } };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const x = $('Extract Inputs').item.json;
return { json: { ok: true, qs: x.qs, filters: x.filters } };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const rows = allOf('Query Alerts');

// Group by alert_type so the page can render per-type sections
const byType = {};
const byStatus = {};
const bySeverity = {};
rows.forEach(function (a) {
  const t = a.alert_type || 'other';
  if (!byType[t]) byType[t] = [];
  byType[t].push(a);
  byStatus[a.status || 'open']    = (byStatus[a.status || 'open']    || 0) + 1;
  bySeverity[a.severity || 'info']= (bySeverity[a.severity || 'info']|| 0) + 1;
});

return { json: {
  ok: true,
  alerts: rows,
  by_type: byType,
  by_status: byStatus,
  by_severity: bySeverity,
  counts: {
    total:        rows.length,
    open:         byStatus.open || 0,
    acknowledged: byStatus.acknowledged || 0,
    resolved:     byStatus.resolved || 0,
    critical:     bySeverity.critical || 0,
    warning:      bySeverity.warning || 0,
    info:         bySeverity.info || 0
  },
  filters: $('Check Admin').item.json.filters
} };
